// Import required libraries
import axios from 'axios';

// Define constants for client ID, redirect URI, authorization URL and token endpoint
const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authUrl = 'https://your-auth-server.com/oauth2/authorize';
const tokenEndpoint = 'https://your-auth-server.com/oauth2/token';

// Function to handle authentication flow
async function authenticate() {
  try {
    // Request authorization code
    const response = await fetch(`${authUrl}?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=code`, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      }
    });

    if (response.ok) {
      // Get authorization code from URL
      const urlParams = new URLSearchParams(window.location.search);
      const code = urlParams.get('code');

      // Exchange code for access token
      const tokenResponse = await fetch(tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${redirectUri}`
      });

      if (tokenResponse.ok) {
        // Get access token from response
        const tokenData = await tokenResponse.json();
        const accessToken = tokenData.access_token;

        // Store access token in local storage
        localStorage.setItem('accessToken', accessToken);

        // Make API request using access token
        const apiResponse = await axios.get('/api/endpoint', {
          headers: {
            Authorization: `Bearer ${accessToken}`
          }
        });

        console.log(apiResponse.data);
      } else {
        throw new Error(`Failed to exchange code for access token`);
      }
    } else {
      throw new Error('Failed to request authorization code');
    }
  } catch (error) {
    console.error(error);
  }
}

// Call authenticate function on page load
authenticate();